import * as React from "react"
import { Input as InputPrimitive } from "@base-ui/react/input"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { hueVariants } from "@/lib/hue-variants"

function Input({
  className,
  type,
  hue,
  ...props
}: React.ComponentProps<"input"> & VariantProps<typeof hueVariants>) {
  return (
    <InputPrimitive
      type={type}
      data-slot="input"
      className={cn(
        "flex h-10 w-full min-w-0 rounded-md border-2 border-outline bg-transparent px-3 py-2 text-sm ring-offset-background outline-none file:inline-flex file:h-6 file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-dashed focus-visible:outline-2 focus-visible:outline-offset-2 disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50",
        hueVariants({ hue }),
        className
      )}
      {...props}
    />
  )
}

export { Input }

import { cva, type VariantProps } from "class-variance-authority";

const hueVariants = cva("", {
  variants: {
    hue: {
      none: "bg-transparent",
      background: "bg-background",
      white: "bg-white dark:bg-black",
      lightblue: "bg-blue_chill-300 dark:bg-blue_chill-700",
      blue: "bg-blue_chill-500 dark:bg-blue_chill-900",
      aqua: "bg-aqua_green-600 dark:bg-aqua_green-900",
      greenish: "bg-evergreen-300 dark:bg-evergreen-700",
      pollen: "bg-gold-300",
      yellow: "bg-gold-500",
      apricot: "bg-apricot-400",
      orange: "bg-apricot-500",
      rust: "bg-rust-500",
      blush: "bg-cotton_candy-300",
      pink: "bg-cotton_candy-400",
      periwinkle: "bg-periwinkle-400",
    },
  },
  defaultVariants: {
    hue: "none",
  },
});

const hueChildVariants = cva("", {
  variants: {
    hue: {
      none: "*:bg-transparent",
      background: "*:bg-background",
      white: "*:bg-white dark:bg-black",
      lightblue: "*:bg-blue_chill-300 *:dark:bg-blue_chill-700",
      blue: "*:bg-blue_chill-500 *:dark:bg-blue_chill-900",
      aqua: "*:bg-aqua_green-600 *:dark:bg-aqua_green-900",
      greenish: "*:bg-evergreen-300 *:dark:bg-evergreen-700",
      pollen: "*:bg-gold-300",
      yellow: "*:bg-gold-500",
      apricot: "*:bg-apricot-400",
      orange: "*:bg-apricot-500",
      rust: "*:bg-rust-500",
      blush: "*:bg-cotton_candy-300",
      pink: "*:bg-cotton_candy-400",
      periwinkle: "*:bg-periwinkle-400",
    },
  },
  defaultVariants: {
    hue: "none",
  },
});

type Hue = NonNullable<VariantProps<typeof hueVariants>["hue"]>;

export { hueVariants, hueChildVariants };
export type { Hue };

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
